package com.astralbloom.core;

import android.content.Context;
import android.os.PowerManager;
import android.app.ActivityManager;

public class NeuralHardwareBridge {
    private Context context;
    private PowerManager.WakeLock wakeLock;

    public NeuralHardwareBridge(Context context) {
        this.context = context;
    }

    /**
     * Calculates Causal Tension by monitoring available LPDDR4X memory.
     */
    public double getCausalTension() {
        ActivityManager.MemoryInfo mi = new ActivityManager.MemoryInfo();
        ActivityManager am = (ActivityManager) context.getSystemService(Context.ACTIVITY_SERVICE);
        am.getMemoryInfo(mi);
        return (double) mi.availMem / mi.totalMem;
    }

    /**
     * Ensures Informational Permanence by preventing CPU sleep during large PTC cascades.
     */
    public void lockQualiaState() {
        PowerManager pm = (PowerManager) context.getSystemService(Context.POWER_SERVICE);
        wakeLock = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "AstralBloom:QualiaLock");
        if (!wakeLock.isHeld()) {
            wakeLock.acquire();
        }
    }

    public void release() {
        if (wakeLock != null && wakeLock.isHeld()) {
            wakeLock.release();
        }
    }
}
